import type { AdventurerClass, AgeCategory, FoodPreference } from "~/data/adventurers";
import type { Race, Origin } from "~/data/adventurers";

export interface PremadeCharacter {
  id: string;
  name: string;
  class: AdventurerClass;
  race: Race;
  origin: Origin;
  age: AgeCategory;
  portrait: string;  // filename without extension
  foodPreference: FoodPreference;
  trait?: string;     // backstory trait ID — will be assigned later
  backstory?: string; // unique personal backstory
}

export const PREMADE_CHARACTERS: PremadeCharacter[] = [
  { id: "char_000", name: "Brenna Thornwood", class: "archer", race: "human", origin: "ashwick", age: "middle", portrait: "brenna_thornwood", foodPreference: "sweet", backstory: "Brenna learned to shoot keeping crows off her father's barley fields; she left the Hearthlands after the taxman took the last harvest and the farm with it." },
  { id: "char_001", name: "Ellie Coldwell", class: "archer", race: "human", origin: "ashwick", age: "middle", portrait: "ellie_coldwell", foodPreference: "spicy", backstory: "Ellie learned to shoot in her father Leofric's smithy yard, aiming at rats between the coal heaps; when the Ashford army stopped paying and the family had to move on, she grabbed a bow and followed him south with her brother Finley." },
  { id: "char_002", name: "Isla Foxglove", class: "archer", race: "human", origin: "ashwick", age: "young", portrait: "isla_foxglove", foodPreference: "hearty", backstory: "Isla kept her sisters fed by poaching deer on Church lands, and when the Inquisitors came knocking about Elara's magic, she packed their things before dawn — a big sister doesn't let her little sister run alone." },
  { id: "char_003", name: "Aldric Blackwood", class: "archer", race: "human", origin: "ashwick", age: "mature", portrait: "aldric_blackwood", foodPreference: "smoky", backstory: "Aldric spent twenty years as a gamekeeper on a Blackwood estate until the lord's son accused him of theft to cover his own debts; he left before the magistrate could rule." },
  { id: "char_004", name: "Cedric Ashford", class: "archer", race: "human", origin: "ashwick", age: "middle", portrait: "cedric_ashford", foodPreference: "fresh", backstory: "Grandson of Elder Rowena, born and raised in the Thornveil among elves and ancient oaks. Cedric learned to shoot from Silvaneth rangers and carries the Ashford name like a question he hasn't answered yet — half forest child, half heir to a court that disowned his grandmother." },
  { id: "char_005", name: "Gareth Thornwood", class: "archer", race: "human", origin: "ashwick", age: "middle", portrait: "gareth_thornwood", foodPreference: "sweet", backstory: "Gareth deserted his post on the northern marches after his company was ordered to burn a village for unpaid tithes; he reckons the frontier won't check his papers." },
  { id: "char_006", name: "Maren Greystone", class: "assassin", race: "human", origin: "ashwick", age: "middle", portrait: "maren_greystone", foodPreference: "spicy", backstory: "Maren kept the books for a Hearthlands merchant guild until she discovered they were laundering coin for the Church's Inquisition — she made sure certain ledgers disappeared, and then so did she." },
  { id: "char_007", name: "Elspeth Ravencroft", class: "assassin", race: "human", origin: "ashwick", age: "old", portrait: "elspeth_ravencroft", foodPreference: "hearty", backstory: "Elspeth has outlived three husbands, two of whom deserved what they got. After the second — a Blackwood — she took her son Edmund and disappeared so completely the family never found them. She raised him on the road, teaching him to stay quiet, watch the exits, and never trust loud men. She came south because the third husband's family started asking uncomfortable questions." },
  { id: "char_008", name: "Lyra Emberheart", class: "assassin", race: "human", origin: "ashwick", age: "young", portrait: "lyra_emberheart", foodPreference: "smoky", backstory: "No family, no name worth keeping. Lyra raised herself in the streets, stealing to eat and killing anyone who tried to take what little she had. When there was nothing left to stay for, she walked out of the city and sold the only skills she owns." },
  { id: "char_009", name: "Edmund Blackwood", class: "assassin", race: "human", origin: "ashwick", age: "middle", portrait: "edmund_blackwood", foodPreference: "fresh", backstory: "Everything Edmund knows, his mother taught him — stay small, stay quiet, a knife is faster than an argument. She raised him on the road after leaving his father's family, and no one ever found them. He carries the Blackwood name on old papers, but he's his mother's son through and through." },
  { id: "char_010", name: "Roderick Ashford", class: "assassin", race: "human", origin: "ashwick", age: "middle", portrait: "roderick_ashford", foodPreference: "sweet", backstory: "Roderick served the Ashford court as a \"diplomatic courier,\" which is a polite way of saying he solved problems that couldn't be solved politely; he left after the problems started including people he knew." },
  { id: "char_011", name: "Finley Coldwell", class: "assassin", race: "human", origin: "ashwick", age: "young", portrait: "finley_coldwell", foodPreference: "spicy", backstory: "Finley was an apprentice locksmith who discovered he was better at opening doors that weren't his, and the Inquisition doesn't distinguish between a curious boy and a burglar." },
  { id: "char_012", name: "Elinor Whitmore", class: "priest", race: "human", origin: "ashwick", age: "middle", portrait: "elinor_whitmore", foodPreference: "hearty", backstory: "Elinor was a parish healer who prayed over every poultice she made, until the Inquisition ruled that her prayers too closely resembled incantations." },
  { id: "char_013", name: "Anwen Greystone", class: "priest", race: "human", origin: "ashwick", age: "middle", portrait: "anwen_greystone", foodPreference: "smoky", backstory: "Anwen tended the dead in a Greystone family crypt and swore she could feel their peace — the Church called it communion with Netheron and stripped her vestments." },
  { id: "char_014", name: "Matilda Wren", class: "priest", race: "human", origin: "ashwick", age: "middle", portrait: "matilda_wren", foodPreference: "fresh", backstory: "Matilda was a convent sister who asked too many questions about why the Doctrine of Silence forbade healing magic when children were dying of fever in the streets." },
  { id: "char_015", name: "Oswin Holloway", class: "priest", race: "human", origin: "ashwick", age: "middle", portrait: "oswin_holloway", foodPreference: "sweet", backstory: "Oswin prayed while his brother Cuthbert brewed, and together they cured fevers the Church said only God could heal. When the Inquisition sentenced them both to burn for it, they fled the monastery by night — Oswin still believes they did holy work, and he'll argue the point with anyone." },
  { id: "char_016", name: "Benedict Ashmore", class: "priest", race: "human", origin: "ashwick", age: "middle", portrait: "benedict_ashmore", foodPreference: "spicy", backstory: "Benedict lit candles for every soul the Inquisition took in his village, and when the pyre-smoke finally choked his faith, he walked south carrying nothing but his censer." },
  { id: "char_017", name: "Aldwin Stonebridge", class: "priest", race: "human", origin: "ashwick", age: "middle", portrait: "aldwin_stonebridge", foodPreference: "hearty", backstory: "Aldwin kept a small chapel that sheltered anyone who needed it — refugees, runaways, no questions asked. When his younger brother Alaric showed up with the Inquisition on his heels, Aldwin didn't hesitate. He hid him with the others, and when the Inquisitors found them all, they fled together. He'll never say it out loud, but he's fiercely proud of the boy." },
  { id: "char_018", name: "Bronwyn Ashford", class: "warrior", race: "human", origin: "ashwick", age: "middle", portrait: "bronwyn_ashford", foodPreference: "smoky", backstory: "Granddaughter of Elder Rowena and twice as loud about it. Bronwyn grew up sparring with Silvaneth sentinels in the Thornveil and swinging a blade before she could read — she left the forest with her brother Cedric not to escape it, but to see what else in the world is worth defending." },
  { id: "char_019", name: "Helga Ironbark", class: "warrior", race: "human", origin: "ashwick", age: "middle", portrait: "helga_ironbark", foodPreference: "fresh", backstory: "Helga hauled ironbark logs alongside men who never let her forget she wasn't one of them — years of remarks, shoves, hands where they shouldn't be, and wages docked for complaining. The last foreman who touched her didn't get a broken jaw. He didn't get up. She took her axe and left." },
  { id: "char_020", name: "Morgause Dunwall", class: "warrior", race: "human", origin: "ashwick", age: "old", portrait: "morgause_dunwall", foodPreference: "sweet", backstory: "Thirty years commanding the border garrisons, and the army thanked her with a forced retirement and a pension that wouldn't feed a dog. Morgause knows she's old. She also knows she can still outfight and outthink half the officers who replaced her, and she's not done yet." },
  { id: "char_021", name: "Godric Thornwood", class: "warrior", race: "human", origin: "ashwick", age: "middle", portrait: "godric_thornwood", foodPreference: "spicy", backstory: "Godric was a farmer's son built like an oak, who joined the levy to escape poverty and deserted the levy to escape cruelty." },
  { id: "char_022", name: "Leofric Coldwell", class: "warrior", race: "human", origin: "ashwick", age: "middle", portrait: "leofric_coldwell", foodPreference: "hearty", backstory: "Leofric was a blacksmith who made swords for the Ashford army until they stopped paying; he kept the last blade he forged and went looking for someone who would." },
  { id: "char_023", name: "Halden Greystone", class: "warrior", race: "human", origin: "ashwick", age: "middle", portrait: "halden_greystone", foodPreference: "smoky", backstory: "Halden guarded a Greystone quarry for twelve years and watched the wages shrink while the tithes grew, until guarding someone else's stone felt like guarding his own chains." },
  { id: "char_024", name: "Gwendolen Hearthwood", class: "wizard", race: "human", origin: "ashwick", age: "middle", portrait: "gwendolen_hearthwood", foodPreference: "fresh", backstory: "Gwendolen's hearth-fire bent toward her hands since she was a girl, and when the Hearthwood family name wasn't enough to protect her from the Inquisition, she fled south where the Church's reach falters." },
  { id: "char_025", name: "Isolde Whitmore", class: "wizard", race: "human", origin: "ashwick", age: "middle", portrait: "isolde_whitmore", foodPreference: "sweet", backstory: "Isolde was a scribe at the university who found forbidden texts walled up in the library's east wing; she copied what she could and vanished the night before the Inquisitors arrived to burn them." },
  { id: "char_026", name: "Elara Foxglove", class: "wizard", race: "human", origin: "ashwick", age: "young", portrait: "elara_foxglove", foodPreference: "spicy", backstory: "Elara is barely sixteen and already on the run — the neighbor's boy saw light dancing between her fingers, and the Inquisitors came that same week. Her sister Isla woke her before dawn and they haven't stopped moving since." },
  { id: "char_027", name: "Merrick Ravencroft", class: "wizard", race: "human", origin: "ashwick", age: "middle", portrait: "merrick_ravencroft", foodPreference: "hearty", backstory: "Merrick studied the old histories in the Ravencroft family archives until he realized the \"myths\" were instructions; the Inquisition burned the archive, but Merrick was already gone." },
  { id: "char_028", name: "Cuthbert Holloway", class: "wizard", race: "human", origin: "ashwick", age: "middle", portrait: "cuthbert_holloway", foodPreference: "smoky", backstory: "Cuthbert mixed the tinctures while his brother Oswin said the prayers, and people stopped dying. The Inquisition called it heresy and sentenced them both to the pyre — they were gone before sunrise. Cuthbert doesn't talk about God the way Oswin does, but he knows the cures worked, and that's enough." },
  { id: "char_029", name: "Alaric Stonebridge", class: "wizard", race: "human", origin: "ashwick", age: "middle", portrait: "alaric_stonebridge", foodPreference: "fresh", backstory: "Alaric's magic came early and strong, and in the Hearthlands that's a death sentence. When the Inquisition marked him, he ran to the only safe place he knew: his brother Aldwin's chapel. He brought trouble with him, and they've been running together since." },
  { id: "char_030", name: "Clover Meadbrook", class: "archer", race: "dwarf", origin: "feldgrund", age: "young", portrait: "clover_meadbrook", foodPreference: "sweet", backstory: "Clover won every harvest fair archery contest in the hill-towns and figured the world owed her a bigger target. She didn't ask her grandmother to come. She specifically told her not to. Nettle came anyway, and Clover will complain about it to anyone who'll listen — but she sleeps better knowing the old woman's tent is next to hers." },
  { id: "char_031", name: "Barley Hearthstone", class: "archer", race: "dwarf", origin: "feldgrund", age: "mature", portrait: "barley_hearthstone", foodPreference: "spicy", backstory: "Barley spent twenty years guarding the family hop fields from deer and decided his aim was wasted on anything that wasn't paying him properly. When his brother Tobias said he was heading south to feed settlers, Barley figured someone ought to watch his back — and the frontier probably needs ale too." },
  { id: "char_032", name: "Rosemary Alewell", class: "assassin", race: "dwarf", origin: "feldgrund", age: "mature", portrait: "rosemary_alewell", foodPreference: "hearty", backstory: "Rosemary ran the most popular inn in three counties while her husband Thistledown brewed the ale that made it famous. He handled the recipes, she handled the dangerous guests — and the best way to handle dangerous guests is to handle them before they know you're dangerous." },
  { id: "char_033", name: "Pippin Barrelhouse", class: "assassin", race: "dwarf", origin: "feldgrund", age: "mature", portrait: "pippin_barrelhouse", foodPreference: "smoky", backstory: "Pippin looks like a cheerful innkeeper who's had too many of his own pies, and that is exactly the last thing several people thought before things went dark. His brother Bramble does the fighting out front — Pippin handles what Bramble shouldn't have to." },
  { id: "char_034", name: "Hazel Hillfoot", class: "priest", race: "dwarf", origin: "feldgrund", age: "old", portrait: "hazel_hillfoot", foodPreference: "fresh", backstory: "She has buried more friends than she can count, blessed more cradles than she can remember, and came south because new settlements need someone who knows how to do both." },
  { id: "char_035", name: "Tobias Hearthstone", class: "priest", race: "dwarf", origin: "feldgrund", age: "mature", portrait: "tobias_hearthstone", foodPreference: "sweet", backstory: "Tobias kept a hill-chapel where the sermon always ended with fresh bread and good counsel. When settlers headed south, he followed — bread rises better when someone needs it. His brother Barley came along to keep him safe, or so Barley says. Tobias suspects it's really about finding new customers for the family ale." },
  { id: "char_036", name: "Primrose Copperkettle", class: "warrior", race: "dwarf", origin: "feldgrund", age: "mature", portrait: "primrose_copperkettle", foodPreference: "spicy", backstory: "She swung a copper kettle at a bandit once and discovered she had a talent that was wasted on brewing — though she still brews on rest days." },
  { id: "char_037", name: "Bramble Barrelhouse", class: "warrior", race: "dwarf", origin: "feldgrund", age: "mature", portrait: "bramble_barrelhouse", foodPreference: "hearty", backstory: "Bramble came south with three barrels of ale, a mail shirt, and his brother Pippin — who he keeps an eye on, because Pippin's idea of solving problems is quieter than Bramble is comfortable with." },
  { id: "char_038", name: "Nettle Meadbrook", class: "wizard", race: "dwarf", origin: "feldgrund", age: "old", portrait: "nettle_meadbrook", foodPreference: "smoky", backstory: "Nettle had no intention of leaving her garden, her kettle, or her hill. Then her granddaughter Clover packed a bag and announced she was off to see the world, and what was Nettle supposed to do — let the girl get herself killed? She grumbles about the road, the food, and the weather, but she wouldn't trade a single miserable mile of it." },
  { id: "char_039", name: "Thistledown Alewell", class: "wizard", race: "dwarf", origin: "feldgrund", age: "old", portrait: "thistledown_alewell", foodPreference: "fresh", backstory: "Thistledown spent fifty years perfecting an ale that brews itself, while his wife Rosemary kept the inn running and the trouble quiet. He considers adventuring a pleasant way to pass the time while waiting for the fermentation cycle to finish — and Rosemary wasn't about to let him wander off alone." },
  { id: "char_040", name: "Yvaine Clairdelune", class: "archer", race: "elf", origin: "hautscieux", age: "middle", portrait: "yvaine_clairdelune", foodPreference: "sweet", backstory: "The Clairdelune spire fell without warning — one morning it was there, the next it was rubble on the valley floor. Yvaine climbed down from the ruins with her bow, her dignity, and her father Florent, and absolutely no intention of discussing it." },
  { id: "char_041", name: "Lucien Fontargent", class: "archer", race: "elf", origin: "hautscieux", age: "middle", portrait: "lucien_fontargent", foodPreference: "spicy", backstory: "Lucien was on watch when the Fourth Quarter collapsed. His bridge went with it, and people he was supposed to protect went with the bridge. His brother Thibault pulled survivors from the rubble — Lucien just stood there. He doesn't talk about it. He keeps watch now out of habit, because stopping means remembering." },
  { id: "char_042", name: "Sylvaine Feuillemorte", class: "assassin", race: "elf", origin: "hautscieux", age: "middle", portrait: "sylvaine_feuillemorte", foodPreference: "hearty", backstory: "Sylvaine handled quiet problems for the Archivists alongside Armand, and somewhere along the way she slipped something into his drink to make sure he'd stay. She doesn't know he was already in love before the first drop — and the guilt of it sits heavier than any blade she's carried. They left together when they discovered their shadow work was burying the truth about the falling cities." },
  { id: "char_043", name: "Armand Lunargent", class: "assassin", race: "elf", origin: "hautscieux", age: "middle", portrait: "armand_lunargent", foodPreference: "smoky", backstory: "Armand was in love with Sylvaine long before she ever reached for that vial — he just never told her. He lets her believe what she believes, because telling her the truth would mean admitting he'd have followed her anywhere, and that kind of vulnerability is harder than any mission they've run together." },
  { id: "char_044", name: "Celeste Aubepine", class: "priest", race: "elf", origin: "hautscieux", age: "middle", portrait: "celeste_aubepine", foodPreference: "fresh", backstory: "Last princess of the Aubepine dynasty, which ruled the high spires before the Sundering. The crown has been passed from mother to daughter for longer than anyone can count — a circlet of light that no living mage knows how to forge. When the spires began to fall, Celeste carried it down from the sky. A queen with no kingdom, but the crown still shines." },
  { id: "char_045", name: "Florent Clairdelune", class: "priest", race: "elf", origin: "hautscieux", age: "middle", portrait: "florent_clairdelune", foodPreference: "sweet", backstory: "Florent ministered to the refugees in the lower spires — the ones crumbling fastest — and preached that faith would hold them up. When the Clairdelune spire fell and he walked out of the rubble with his daughter Yvaine, he finally understood the faith he'd been preaching: not in the stones, but in each other." },
  { id: "char_046", name: "Elowen Rosecendre", class: "warrior", race: "elf", origin: "hautscieux", age: "middle", portrait: "elowen_rosecendre", foodPreference: "spicy", backstory: "She was honor guard to a scholar-house that voted to descend gracefully rather than plummet unexpectedly, and she carries their banner like it is not a surrender flag." },
  { id: "char_047", name: "Thibault Fontargent", class: "warrior", race: "elf", origin: "hautscieux", age: "middle", portrait: "thibault_fontargent", foodPreference: "hearty", backstory: "Thibault pulled twelve people from the rubble when the Fourth Quarter fell, and hasn't stopped moving since. If he keeps fighting, keeps holding lines, he doesn't have to think about the ones he didn't reach. His brother Lucien went quiet after that day — Thibault went the other way." },
  { id: "char_048", name: "Vivienne Lunargent", class: "wizard", race: "elf", origin: "hautscieux", age: "middle", portrait: "vivienne_lunargent", foodPreference: "smoky", backstory: "Her thesis on gravitational decay in floating architecture was deemed \"alarmist\" three years before her university fell out of the sky — she no longer submits work for peer review." },
  { id: "char_049", name: "Dorien Brumesang", class: "wizard", race: "elf", origin: "hautscieux", age: "middle", portrait: "dorien_brumesang", foodPreference: "fresh", backstory: "He archives every scrap of pre-Sundering knowledge he can find, copying texts onto vellum because the crystal-libraries are shattering, and calls this work too important for pride." },
  { id: "char_050", name: "Dagna Deepforge", class: "archer", race: "dwarf", origin: "khazdurim", age: "middle", portrait: "dagna_deepforge", foodPreference: "sweet", backstory: "Dagna watched a demon tear her best friend apart in front of her, and she put an arrow through its eye too late. She swore she'd hunt every one that slipped through the cracks, and her grandfather Olvir left the Seals to go with her. She knows what that cost him, and it makes her angrier — at the demons, at herself, at a world that makes people choose like that." },
  { id: "char_051", name: "Borin Stonefist", class: "archer", race: "dwarf", origin: "khazdurim", age: "middle", portrait: "borin_stonefist", foodPreference: "spicy", backstory: "Borin manned a crossbow post above the second Seal for eleven years, and the day he heard something knock from the other side, he ran. He's not proud of it. He's out here killing demons and anything else that bleeds evil, because if he can't undo the running, he can at least make sure the rest of his life counts for something." },
  { id: "char_052", name: "Hilda Copperbeard", class: "assassin", race: "dwarf", origin: "khazdurim", age: "middle", portrait: "hilda_copperbeard", foodPreference: "hearty", backstory: "Hilda did the quiet work for the Anvil Guard — eliminating dwarves who tried to break the Seals. She never questioned the targets until the names started feeling wrong: loyal people, good people, elders she'd known her whole life. The demons weren't just breaking through stone — they were corrupting the Watch itself, turning Hilda into their weapon. She fled the night her husband Grimm's name appeared on the list, and she pressed him to come with her before she could explain why." },
  { id: "char_053", name: "Thrain Fireaxe", class: "assassin", race: "dwarf", origin: "khazdurim", age: "middle", portrait: "thrain_fireaxe", foodPreference: "smoky", backstory: "Thrain saw what is behind the third Seal, and the weight of that knowledge is why he drinks. His wife couldn't reach him anymore — he was there but not there, always staring at something she couldn't see. She told him to leave until he came back to himself. He never did. He hunts demons now, because it's the only thing that quiets his mind. He keeps a locket with a family portrait in it and doesn't open it." },
  { id: "char_054", name: "Brunhild Hammerfall", class: "priest", race: "dwarf", origin: "khazdurim", age: "middle", portrait: "brunhild_hammerfall", foodPreference: "fresh", backstory: "Brunhild held the prayer-wards while her sister Magna held the runes, and together they kept the second Seal for thirty years. Then Bahruun, Warlord of the Third Depth, broke through and killed their entire team. He yawned, looked at the two old women standing in the blood of their friends, and said: \"You smell like prayer and rust. Go home, grandmothers.\" Then he walked past them. They hear it every single day. They left the mountain to make sure he hears them back." },
  { id: "char_055", name: "Durin Stonefist", class: "priest", race: "dwarf", origin: "khazdurim", age: "middle", portrait: "durin_stonefist", foodPreference: "sweet", backstory: "Durin spent forty years tending the Hall of Names in the Ironspine — the sacred cavern where every fallen Khazdurim is carved into stone. One morning his granddaughter Sigrun's name appeared on the wall, freshly carved, in a hand he didn't recognize. She was alive and well. He found her, took her, and left the mountain. He doesn't know what wrote her name among the dead, but he wasn't going to wait and find out." },
  { id: "char_056", name: "Sigrun Stonefist", class: "warrior", race: "dwarf", origin: "khazdurim", age: "middle", portrait: "sigrun_stonefist", foodPreference: "spicy", backstory: "Sigrun left the mountain before the worst of it — she'd seen enough to know she wanted to fight in the open, not behind sealed doors. When her grandfather Durin showed up at her camp one day, she didn't ask why. She knows him well enough to know he wouldn't have left the Hall of Names unless something forced his hand." },
  { id: "char_057", name: "Grimm Copperbeard", class: "warrior", race: "dwarf", origin: "khazdurim", age: "middle", portrait: "grimm_copperbeard", foodPreference: "hearty", backstory: "Grimm doesn't fully understand why Hilda woke him in the dark and told him they were leaving. She wouldn't explain, and the look in her eyes said not to ask. He forged his armor in the deep furnaces, quenched it in glacier-melt, and walked out of the mountain with his wife. He doesn't need to know everything — he just needs something to hit, and demons will do fine." },
  { id: "char_058", name: "Magna Hammerfall", class: "wizard", race: "dwarf", origin: "khazdurim", age: "middle", portrait: "magna_hammerfall", foodPreference: "smoky", backstory: "Magna maintained the rune-locks while her sister Brunhild held the prayers, and for thirty years nothing got through. The night the Warlord of the Third Depth broke through, their team died and Bahruun yawned and called them grandmothers and told them to go home. Magna carries a list of every name they lost that night, and for each one she intends to take something back. Starting with him." },
  { id: "char_059", name: "Olvir Deepforge", class: "wizard", race: "dwarf", origin: "khazdurim", age: "middle", portrait: "olvir_deepforge", foodPreference: "fresh", backstory: "Olvir spent forty years reinforcing the Seals — rune-wards, stone-binding, everything he knew. When Dagna walked out of the mountain with murder in her eyes and a dead friend behind her, he made the hardest choice of his life: he left the Seals to follow her. Someone else will have to hold the line. His granddaughter comes first, and he'll carry that guilt until he dies." },
  { id: "char_060", name: "Farah Al-Rashid", class: "archer", race: "human", origin: "khorvani", age: "mature", portrait: "farah_al_rashid", foodPreference: "sweet", backstory: "Farah carries the Al-Rashid name and the weight of Varek's blood — every border guard looks twice, every innkeeper charges double. She lost an eye to men who came for the name, not for her. She doesn't complain. One arrow, one kill, move on. She gave her daughter Nadia her father's surname to keep her safe from the curse of being an Al-Rashid, and raised her to be quiet, careful, and dangerous." },
  { id: "char_061", name: "Zahra Khan", class: "archer", race: "human", origin: "khorvani", age: "middle", portrait: "zahra_khan", foodPreference: "spicy", backstory: "Zahra doesn't know where she came from — she was surviving alone in the wilds when old Arjun found her, half-starved and feral, with a makeshift bow and the eyes of something that had already learned to kill. He gave her his name, taught her to aim properly, and she gave him a reason to keep going. She still doesn't talk much, but she doesn't miss." },
  { id: "char_062", name: "Priya Desai", class: "archer", race: "human", origin: "khorvani", age: "young", portrait: "priya_desai", foodPreference: "hearty", backstory: "When the Desai fortune turned out to be forged ledgers and borrowed gold, allied families fell with it and no one offered the children shelter. Priya was the eldest. She picked up a bow, learned to hunt, and fed her younger siblings because no one else was going to. She still doesn't talk about the house they lost." },
  { id: "char_063", name: "Arjun Khan", class: "archer", race: "human", origin: "khorvani", age: "mature", portrait: "arjun_khan", foodPreference: "smoky", backstory: "Arjun trained border riders for twenty years and thought he'd die on the frontier with a bow in his hand. Then he found a half-wild girl in the desert, alone and starving, who snarled at him when he offered bread. He couldn't leave her. He gave her his name, taught her everything he knew, and discovered that the old horse-archer had one more thing left to live for." },
  { id: "char_064", name: "Ravi Mansour", class: "archer", race: "human", origin: "khorvani", age: "middle", portrait: "ravi_mansour", foodPreference: "fresh", backstory: "Ravi has guided caravans across the Amber Crossroads for longer than most merchants have been alive. He knows every dune, every dry well, every shortcut the maps don't show. He came north because the trade roads are dying and a man who knows the desert isn't much use when nobody crosses it anymore." },
  { id: "char_065", name: "Idris Hassan", class: "archer", race: "human", origin: "khorvani", age: "middle", portrait: "idris_hassan", foodPreference: "sweet", backstory: "A former astronomy student who traded his telescope for a longbow when his observatory was defunded. He still navigates by the stars and insists the two disciplines aren't so different — both require patience and a steady eye." },
  { id: "char_066", name: "Leila Mirza", class: "assassin", race: "human", origin: "khorvani", age: "mature", portrait: "leila_mirza", foodPreference: "spicy", backstory: "Leila was a diplomatic courier who spent years crossing borders no one else could cross, carrying messages no one else could be trusted with. She speaks four languages, knows which officials can be bribed, and disappears so completely between jobs that even her employers forget what she looks like. That's the way she prefers it." },
  { id: "char_067", name: "Nadia Patel", class: "assassin", race: "human", origin: "khorvani", age: "middle", portrait: "nadia_patel", foodPreference: "hearty", backstory: "Nadia carries her father's name, not her mother Farah's — and that was deliberate. She doesn't know the full weight of being an Al-Rashid, only that her mother lost an eye for it and taught her to be quiet, careful, and very good with a blade. She thinks she's just a Patel. She doesn't know why strangers sometimes stare at her face and see someone else." },
  { id: "char_068", name: "Samira Khan", class: "assassin", race: "human", origin: "khorvani", age: "young", portrait: "samira_khan", foodPreference: "smoky", backstory: "Grew up in the sprawling bazaars picking pockets to survive after her parents died of plague. She's fast, she's quiet, and she's tired of people underestimating the skinny girl with the sad story." },
  { id: "char_069", name: "Tariq Hassan", class: "assassin", race: "human", origin: "khorvani", age: "mature", portrait: "tariq_hassan", foodPreference: "fresh", backstory: "A former trade-guild enforcer who collected debts for the merchant houses for too many years. He quit when they asked him to collect from a widow whose husband he'd already dealt with, and realized he'd built the debt himself." },
  { id: "char_070", name: "Kiran Sharma", class: "assassin", race: "human", origin: "khorvani", age: "middle", portrait: "kiran_sharma", foodPreference: "sweet", backstory: "Studied alchemy at the Khor'vani academy by day and ran with a street gang by night, until both worlds collided and he was expelled from one and hunted by the other. The frontier seemed like the only direction left." },
  { id: "char_071", name: "Darius Desai", class: "assassin", race: "human", origin: "khorvani", age: "young", portrait: "darius_desai", foodPreference: "spicy", backstory: "Darius was twelve when the Desai name became worthless overnight. While his sister Priya hunted to keep them fed, he disappeared into the streets and learned a different way to survive. He's looking for the creditors who destroyed his family — not to talk." },
  { id: "char_072", name: "Yasmin Farouk", class: "priest", race: "human", origin: "khorvani", age: "middle", portrait: "yasmin_farouk", foodPreference: "hearty", backstory: "Yasmin spent thirty years reading the stars in the great observatory-temples. When a star fell westward — one that no chart predicted and no model explained — she followed it, because her son Hari had found something in the sealed archives that made the falling star terrifying instead of beautiful. Her order called it desertion. She calls it the only sane response." },
  { id: "char_073", name: "Anisa Al-Rashid", class: "priest", race: "human", origin: "khorvani", age: "middle", portrait: "anisa_al_rashid", foodPreference: "smoky", backstory: "Anisa wears the Al-Rashid name like her father Rashid taught her — head high, voice steady, and if anyone has a problem with it, that's their problem. She heals without asking heritage and expects the same courtesy in return. Five hundred years is long enough to atone for one man's sins." },
  { id: "char_074", name: "Miriam Bakhtiar", class: "priest", race: "human", origin: "khorvani", age: "old", portrait: "miriam_bakhtiar", foodPreference: "fresh", backstory: "Has spent sixty years as a healer and has stopped counting how many times patients flinched when they heard her accent. She came west because the frontier doesn't care where your grandmother was born." },
  { id: "char_075", name: "Rohan Joshi", class: "priest", race: "human", origin: "khorvani", age: "mature", portrait: "rohan_joshi", foodPreference: "sweet", backstory: "A temple scholar who wrote extensively on the ethics of empire, arguing that acknowledging Varek's crimes was the first step to transcending them. His temple agreed with the philosophy but not the publicity, and quietly asked him to leave." },
  { id: "char_076", name: "Sanjay Sharma", class: "priest", race: "human", origin: "khorvani", age: "middle", portrait: "sanjay_sharma", foodPreference: "spicy", backstory: "An herbalist and healer who walked away from a comfortable temple posting because the high priest refused to treat non-Khor'vani patients. \"Varek built the road,\" his mother used to say. Sanjay is still deciding where it leads." },
  { id: "char_077", name: "Naveen Desai", class: "priest", race: "human", origin: "khorvani", age: "young", portrait: "naveen_desai", foodPreference: "hearty", backstory: "When the family fell, Naveen turned to prayer because it was the only thing left that was free. He has a good and generous soul — he heals anyone who asks and prays every night for his brother Darius to come to his senses before the anger eats him alive." },
  { id: "char_078", name: "Soraya Khatri", class: "warrior", race: "human", origin: "khorvani", age: "mature", portrait: "soraya_khatri", foodPreference: "smoky", backstory: "A decorated caravan guard-captain who escorted merchants across the desert for fifteen years, and never lost a shipment until the one that carried her daughter. She's been chasing those bandits westward ever since." },
  { id: "char_079", name: "Amira Hassan", class: "warrior", race: "human", origin: "khorvani", age: "middle", portrait: "amira_hassan", foodPreference: "fresh", backstory: "A blacksmith's daughter who picked up a sword because the city guard wouldn't patrol her neighborhood. When the guard finally noticed her, they offered recruitment; she'd already lost respect for the institution." },
  { id: "char_080", name: "Vikram Mansour", class: "warrior", race: "human", origin: "khorvani", age: "middle", portrait: "vikram_mansour", foodPreference: "sweet", backstory: "A wrestler and strongman from the festival circuit who dreamed of something bigger than trophies and applause. He set out west the day after winning the championship, because there was nothing left to prove in the ring." },
  { id: "char_081", name: "Rashid Al-Rashid", class: "warrior", race: "human", origin: "khorvani", age: "middle", portrait: "rashid_al_rashid", foodPreference: "spicy", backstory: "Rashid wears the Al-Rashid name like armor, not a scar. Where his sister Farah hides it, he shouts it. He raised his daughter Anisa to do the same — the name was old before Varek was born, and it'll be standing long after his ghost is dust. He fights twice as hard as anyone because he refuses to let one dead man define his blood." },
  { id: "char_082", name: "Amir Soraya", class: "warrior", race: "human", origin: "khorvani", age: "young", portrait: "amir_soraya", foodPreference: "hearty", backstory: "Left home at sixteen after his mother told him that the world would judge him for his accent and his complexion before it judged his character. He intends to give them something worth judging." },
  { id: "char_083", name: "Layla Bakhtiar", class: "wizard", race: "human", origin: "khorvani", age: "mature", portrait: "layla_bakhtiar", foodPreference: "smoky", backstory: "An astronomer-mage who mapped ley lines along the old Varek trade roads and discovered they were deliberately built to channel power. She published the finding; the Dominion suppressed it. She kept her notes and left." },
  { id: "char_084", name: "Devi Joshi", class: "wizard", race: "human", origin: "khorvani", age: "middle", portrait: "devi_joshi", foodPreference: "fresh", backstory: "A gifted transmuter who dreamed of turning the desert green, but her research funding was cut when the academy decided alchemy was \"too associated with Khor'vani tradition.\" She took her notes and her pride and went somewhere that wanted results over politics." },
  { id: "char_085", name: "Kala Desai", class: "wizard", race: "human", origin: "khorvani", age: "young", portrait: "kala_desai", foodPreference: "sweet", backstory: "Kala barely remembers the old house — she was the youngest when it all came apart. Priya fed her, Naveen prayed over her, and Darius was already gone. She threw herself into magic because it's the one thing that's entirely hers, that no creditor can seize and no scandal can take away." },
  { id: "char_086", name: "Omid Sharma", class: "wizard", race: "human", origin: "khorvani", age: "middle", portrait: "omid_sharma", foodPreference: "spicy", backstory: "A philosophical alchemist who believes magic is just science the world hasn't explained yet. He left the Khor'vani academies because they wanted mystics, and he wanted answers." },
  { id: "char_087", name: "Hari Farouk", class: "wizard", race: "human", origin: "khorvani", age: "young", portrait: "hari_farouk", foodPreference: "hearty", backstory: "Hari's mother Yasmin taught him to read the stars before he could read words — every night before bed, she'd point at the sky and name what she saw. He grew up chasing her passion into the restricted archives, where he found star charts sealed since Varek's time. Not conquest plans — predictions. He told his mother what the charts said about the falling star, and she went pale in a way he'd never seen. They left the observatory together that night." },
  { id: "char_088", name: "Serafina Castellani", class: "archer", race: "human", origin: "meridian", age: "mature", portrait: "serafina_castellani", foodPreference: "smoky", backstory: "Serafina spent fifteen years on the rigging of Corsair galleys, picking off boarding parties with a shortbow; she came ashore when her knees gave out and her captain's debts caught up." },
  { id: "char_089", name: "Ginevra Solari", class: "archer", race: "human", origin: "meridian", age: "mature", portrait: "ginevra_solari", foodPreference: "fresh", backstory: "Ginevra was a merchant's wife who learned to shoot defending cargo ships from pirates, then learned her husband was one of the pirates' best customers." },
  { id: "char_090", name: "Fiora Monteverdi", class: "archer", race: "human", origin: "meridian", age: "middle", portrait: "fiora_monteverdi", foodPreference: "sweet", backstory: "Fiora won a crossbow in a card game in a harbor tavern and discovered she had a natural eye; she's been trading on that luck ever since the Monteverdi family's wine business went sour." },
  { id: "char_091", name: "Chiara Ferraro", class: "archer", race: "human", origin: "meridian", age: "young", portrait: "chiara_ferraro", foodPreference: "spicy", backstory: "Chiara grew up on the docks watching her father haggle and her mother gut fish, and when a Corsair captain offered her a place on his crew for her aim with a sling, she didn't think twice." },
  { id: "char_092", name: "Luciano Castellani", class: "archer", race: "human", origin: "meridian", age: "mature", portrait: "luciano_castellani", foodPreference: "hearty", backstory: "Luciano captained a merchant vessel for the Castellani trading house until a bad storm and a worse insurance claim left him with no ship and a family name that wouldn't vouch for him." },
  { id: "char_093", name: "Matteo Bianchi", class: "archer", race: "human", origin: "meridian", age: "middle", portrait: "matteo_bianchi", foodPreference: "smoky", backstory: "Matteo was a fisher's boy who joined a Corsair crew at fourteen for the money, jumped ship at twenty when the captain turned slaver, and has been freelancing his bowmanship ever since." },
  { id: "char_094", name: "Enzo DeLuca", class: "archer", race: "human", origin: "meridian", age: "middle", portrait: "enzo_deluca", foodPreference: "fresh", backstory: "Enzo ran a crossbow range on the Meridian waterfront — half target-shooting, half debt collection — until he collected from the wrong merchant and woke up with his shop on fire." },
  { id: "char_095", name: "Alessia Ferraro", class: "assassin", race: "human", origin: "meridian", age: "middle", portrait: "alessia_ferraro", foodPreference: "sweet", backstory: "Alessia was a perfumer's daughter who learned that the line between a sleeping draught and a killing dose is mostly a matter of intention; a jilted Ferraro cousin paid her to cross that line once, and once was enough to need a new city." },
  { id: "char_096", name: "Valentina Solari", class: "assassin", race: "human", origin: "meridian", age: "middle", portrait: "valentina_solari", foodPreference: "spicy", backstory: "Valentina danced in the Solari pleasure houses and listened to the secrets men whisper when they think a woman isn't paying attention; she sold those secrets until one buyer wanted silence instead of information." },
  { id: "char_097", name: "Caterina Monteverdi", class: "assassin", race: "human", origin: "meridian", age: "middle", portrait: "caterina_monteverdi", foodPreference: "hearty", backstory: "Caterina managed the Monteverdi family's \"difficult negotiations\" for years — the kind conducted in alleys, not offices — and left when the family decided she knew too many of their difficulties." },
  { id: "char_098", name: "Dante Bianchi", class: "assassin", race: "human", origin: "meridian", age: "mature", portrait: "dante_bianchi", foodPreference: "smoky", backstory: "Dante was a harbor inspector who took bribes from every ship that docked until a Corsair captain offered him something more interesting than coin: a name, a target, and a reason." },
  { id: "char_099", name: "Niccolo DeLuca", class: "assassin", race: "human", origin: "meridian", age: "middle", portrait: "niccolo_deluca", foodPreference: "fresh", backstory: "Niccolo grew up in the tangled streets behind the Meridian fish market, where he learned that a quick knife and quicker feet are worth more than any honest trade." },
  { id: "char_100", name: "Raffaello Castellani", class: "assassin", race: "human", origin: "meridian", age: "middle", portrait: "raffaello_castellani", foodPreference: "sweet", backstory: "Raffaello was the black sheep of the Castellani family — too clever for commerce, too restless for politics — until he found the one trade where both talents pay: making problems disappear." },
  { id: "char_101", name: "Isabella Solari", class: "priest", race: "human", origin: "meridian", age: "mature", portrait: "isabella_solari", foodPreference: "spicy", backstory: "Isabella kept a shrine to Nereia in the harbor quarter and blessed every ship that sailed, asking only for fair winds and honest coin; she left when the Corsair League decided blessings should be taxed like any other service." },
  { id: "char_102", name: "Adriana Corsini", class: "priest", race: "human", origin: "meridian", age: "middle", portrait: "adriana_corsini", foodPreference: "hearty", backstory: "Adriana was a Corsini convent girl who felt Nereia's pull in every tide and finally walked out of chapel and into the surf; she serves the Deep now, not the dry stone prayers of landbound clerics." },
  { id: "char_103", name: "Lucia Ferraro", class: "priest", race: "human", origin: "meridian", age: "young", portrait: "lucia_ferraro", foodPreference: "smoky", backstory: "Lucia prayed for her father's fishing boat every morning and one day Nereia answered — the nets came up so full they nearly sank the vessel, and her father told her, gently, that a gift like that frightens simple fishermen." },
  { id: "char_104", name: "Lorenzo Monteverdi", class: "priest", race: "human", origin: "meridian", age: "middle", portrait: "lorenzo_monteverdi", foodPreference: "fresh", backstory: "Lorenzo was a Monteverdi wine merchant who found more truth in the bottom of a cup than in a ledger, and more grace in a sailor's prayer to Nereia than in any cathedral; he traded his scales for a censer and hasn't regretted it." },
  { id: "char_105", name: "Silvio Bianchi", class: "priest", race: "human", origin: "meridian", age: "middle", portrait: "silvio_bianchi", foodPreference: "sweet", backstory: "Silvio was a ship's surgeon who prayed over every wound he stitched; when a dying sailor recovered in ways the crew called miraculous, Silvio realized the prayers were doing more than he'd thought." },
  { id: "char_106", name: "Marco DeLuca", class: "priest", race: "human", origin: "meridian", age: "young", portrait: "marco_deluca", foodPreference: "spicy", backstory: "Marco heard Nereia's voice in a storm that should have killed him, and when the sea spat him back onto the docks alive, he decided he owed her a life of service in return." },
  { id: "char_107", name: "Vittoria Castellani", class: "warrior", race: "human", origin: "meridian", age: "mature", portrait: "vittoria_castellani", foodPreference: "hearty", backstory: "Vittoria commanded the Castellani family's private guard until a trade war turned into a real one and she lost half her company defending a warehouse full of someone else's silk." },
  { id: "char_108", name: "Bianca Moretto", class: "warrior", race: "human", origin: "meridian", age: "middle", portrait: "bianca_moretto", foodPreference: "smoky", backstory: "Bianca was a dockside brawler who fought in the harbor pits for coin until a Corsair captain told her she was wasting good sword-arm on bad odds; she agreed, took his offer, and never looked back." },
  { id: "char_109", name: "Emilia Ferraro", class: "warrior", race: "human", origin: "meridian", age: "young", portrait: "emilia_ferraro", foodPreference: "fresh", backstory: "Emilia trained at the Ferraro fencing school and dreamed of tournament glory, but tournaments cost entry fees her family couldn't afford, so she took her blade where it could earn instead of spend." },
  { id: "char_110", name: "Giovanni Solari", class: "warrior", race: "human", origin: "meridian", age: "middle", portrait: "giovanni_solari", foodPreference: "sweet", backstory: "Giovanni was a Solari warehouse foreman built like a wine barrel, who picked up a sword when pirates raided the docks and discovered he was better at fighting than counting crates." },
  { id: "char_111", name: "Aldric Monteverdi", class: "warrior", race: "human", origin: "meridian", age: "old", portrait: "aldric_monteverdi", foodPreference: "spicy", backstory: "Aldric has served as a sellsword on both sides of three Corsair trade wars and can't remember which side he started on; he came north because warm-water contracts were drying up faster than the harbors." },
  { id: "char_112", name: "Tomas DeLuca", class: "warrior", race: "human", origin: "meridian", age: "young", portrait: "tomas_deluca", foodPreference: "hearty", backstory: "Tomas got into a duel over a girl, won, and then discovered the loser was a DeLuca cousin — his own family told him to disappear until the grudge cooled, which in Meridian could take a lifetime." },
  { id: "char_113", name: "Serafina Bianchi", class: "wizard", race: "human", origin: "meridian", age: "middle", portrait: "serafina_bianchi", foodPreference: "smoky", backstory: "Serafina was an ink-maker's daughter who discovered that certain old Meridian dye recipes did more than color cloth; her fabrics shimmered with light that didn't come from any thread, and the guild called it fraud before they could call it sorcery." },
  { id: "char_114", name: "Donatella Corsini", class: "wizard", race: "human", origin: "meridian", age: "middle", portrait: "donatella_corsini", foodPreference: "fresh", backstory: "Donatella was a Corsini family astrologer who charted tides and trade winds with uncanny accuracy until her patrons realized her charts worked because the winds were actually obeying her." },
  { id: "char_115", name: "Ornella Castellani", class: "wizard", race: "human", origin: "meridian", age: "old", portrait: "ornella_castellani", foodPreference: "sweet", backstory: "Ornella has been reading the cards and the currents for fifty years in the Castellani harbor quarter; she came north because the cards told her to, and she's never been wrong yet." },
  { id: "char_116", name: "Flavio Ferraro", class: "wizard", race: "human", origin: "meridian", age: "middle", portrait: "flavio_ferraro", foodPreference: "spicy", backstory: "Flavio was a glassblower whose finest pieces seemed to hold captured light long after the furnace cooled; when a Church inspector from the Dominion started asking questions at the export docks, the Ferraro family suggested he travel." },
  { id: "char_117", name: "Prospero Solari", class: "wizard", race: "human", origin: "meridian", age: "old", portrait: "prospero_solari", foodPreference: "hearty", backstory: "Prospero was a navigator whose ships never lost their way, not once in forty years — the Solari family called it genius, the Church called it something else, and Prospero decided not to wait for the verdict." },
  { id: "char_118", name: "Sandro Moretto", class: "wizard", race: "human", origin: "meridian", age: "young", portrait: "sandro_moretto", foodPreference: "smoky", backstory: "Sandro accidentally boiled a pot of dye without a fire beneath it and his master threw him out of the workshop screaming about demons; he figures if he's going to be called a sorcerer, he might as well learn to be one." },
  { id: "char_119", name: "Sigrid Stormvik", class: "archer", race: "human", origin: "nordveld", age: "mature", portrait: "sigrid_stormvik", foodPreference: "fresh", backstory: "Sigrid hunted seal and snow-fox on the outer islands for twenty winters until a storm took her boat, her husband, and her reason to stay." },
  { id: "char_120", name: "Astrid Ravnskog", class: "archer", race: "human", origin: "nordveld", age: "middle", portrait: "astrid_ravnskog", foodPreference: "sweet", backstory: "Astrid could split a raven's feather at forty paces, a skill her father called a gift from Ullvar — she left the frozen islands when there was nothing left worth aiming at." },
  { id: "char_121", name: "Bjorn Steinholm", class: "archer", race: "human", origin: "nordveld", age: "middle", portrait: "bjorn_steinholm", foodPreference: "spicy", backstory: "Bjorn grew up on stories of the old raids and a grandfather's longbow that still sang true; he went south not for conquest, but because the fishing had failed for the third year running." },
  { id: "char_122", name: "Tormund Bjornsen", class: "archer", race: "human", origin: "nordveld", age: "middle", portrait: "tormund_bjornsen", foodPreference: "hearty", backstory: "Tormund's son drowned in the straits last autumn, and his wife said she couldn't bear to watch him stare at the water anymore; he agreed that leaving was kinder than staying." },
  { id: "char_123", name: "Leif Frostvik", class: "archer", race: "human", origin: "nordveld", age: "young", portrait: "leif_frostvik", foodPreference: "smoky", backstory: "Leif is the youngest of six brothers on a farm that can barely feed three, so he took his bow and his father's blessing and walked south before winter." },
  { id: "char_124", name: "Freya Thorssen", class: "assassin", race: "human", origin: "nordveld", age: "mature", portrait: "freya_thorssen", foodPreference: "fresh", backstory: "Freya was a völva's apprentice who learned which herbs heal and which ones don't — she left the islands after using that knowledge on a jarl who'd beaten his thralls to death." },
  { id: "char_125", name: "Ragna Stormvik", class: "assassin", race: "human", origin: "nordveld", age: "middle", portrait: "ragna_stormvik", foodPreference: "sweet", backstory: "Ragna grew up in a raiding family that lost its ship, its honor, and finally its name; she learned to fight quiet because she couldn't afford to fight loud." },
  { id: "char_126", name: "Ylva Ravnskog", class: "assassin", race: "human", origin: "nordveld", age: "young", portrait: "ylva_ravnskog", foodPreference: "spicy", backstory: "Ylva was small for a Nordveld girl and tired of proving herself in the shield-ring, so she learned to win fights before they started instead." },
  { id: "char_127", name: "Fenrir Steinholm", class: "assassin", race: "human", origin: "nordveld", age: "middle", portrait: "fenrir_steinholm", foodPreference: "hearty", backstory: "Fenrir killed a man in a blood feud that everyone agreed was justified, but the dead man's brother was a jarl, and justice bends for jarls." },
  { id: "char_128", name: "Eirik Bjornsen", class: "assassin", race: "human", origin: "nordveld", age: "middle", portrait: "eirik_bjornsen", foodPreference: "smoky", backstory: "Eirik was a whaler who discovered he was steadier with a knife in the dark than on the rolling deck; he doesn't talk about whose throat taught him the difference." },
  { id: "char_129", name: "Sven Frostvik", class: "assassin", race: "human", origin: "nordveld", age: "young", portrait: "sven_frostvik", foodPreference: "fresh", backstory: "Sven stole from the jarl's storehouse during a famine winter to feed his mother, and when they came for him, he learned that running is just another kind of fighting." },
  { id: "char_130", name: "Hilda Thorssen", class: "priest", race: "human", origin: "nordveld", age: "mature", portrait: "hilda_thorssen", foodPreference: "sweet", backstory: "Hilda is a völva who has set bones, delivered children, and spoken with the dead for longer than most people have been alive; she came south because the old gods told her to, and she doesn't argue with them." },
  { id: "char_131", name: "Solveig Stormvik", class: "priest", race: "human", origin: "nordveld", age: "middle", portrait: "solveig_stormvik", foodPreference: "spicy", backstory: "Solveig tends shrines to all seven gods, including Netheron — she sees no contradiction in honoring death alongside life, though the Dominion preachers who've drifted north find it deeply troubling." },
  { id: "char_132", name: "Ingrid Ravnskog", class: "priest", race: "human", origin: "nordveld", age: "young", portrait: "ingrid_ravnskog", foodPreference: "hearty", backstory: "Ingrid heard the gods whispering in the standing stones when she was nine; her mother, a völva, sent her south to learn what the whispers meant before they grew too loud to ignore." },
  { id: "char_133", name: "Halvard Steinholm", class: "priest", race: "human", origin: "nordveld", age: "middle", portrait: "halvard_steinholm", foodPreference: "smoky", backstory: "Halvard carved god-poles for his village and spoke the old rites, but when a Dominion missionary smashed his shrine, he broke the man's arm — the village asked him to leave before the Church sent more." },
  { id: "char_134", name: "Odin Bjornsen", class: "priest", race: "human", origin: "nordveld", age: "old", portrait: "odin_bjornsen", foodPreference: "fresh", backstory: "They call him Odin as a joke he's grown into — one-eyed, grey-bearded, and full of riddles, he wanders because the gods never told him to stop." },
  { id: "char_135", name: "Thorgrim Frostvik", class: "priest", race: "human", origin: "nordveld", age: "old", portrait: "thorgrim_frostvik", foodPreference: "sweet", backstory: "Thorgrim kept the death-rites for three generations of Frostvik dead and says he can feel when Netheron is near; he came south because the god's gaze turned southward, and a priest follows where his god looks." },
  { id: "char_136", name: "Alvar Thorssen", class: "priest", race: "human", origin: "nordveld", age: "young", portrait: "alvar_thorssen", foodPreference: "spicy", backstory: "Alvar was meant to be a warrior like his father, but he kept hearing voices in the wind that spoke of things that hadn't happened yet — his mother recognized the gift and sent him to learn its weight." },
  { id: "char_137", name: "Brynhild Stormvik", class: "warrior", race: "human", origin: "nordveld", age: "middle", portrait: "brynhild_stormvik", foodPreference: "hearty", backstory: "Brynhild swore a shield-oath to her jarl and kept it until the jarl sold her village's fishing rights to a Meridian merchant; an oath to a traitor is no oath at all." },
  { id: "char_138", name: "Gudrun Ravnskog", class: "warrior", race: "human", origin: "nordveld", age: "middle", portrait: "gudrun_ravnskog", foodPreference: "smoky", backstory: "Gudrun came south with her husband's axe and her own fury after raiders from a rival clan burned her homestead; she'd rather fight strangers' wars than sit in the ashes of her own." },
  { id: "char_139", name: "Thyra Steinholm", class: "warrior", race: "human", origin: "nordveld", age: "middle", portrait: "thyra_steinholm", foodPreference: "fresh", backstory: "Thyra served as a housecarl for the Steinholm clan until a dispute over whale-rights turned bloody and she found herself on the losing side of a feud she hadn't started." },
  { id: "char_140", name: "Ragnar Bjornsen", class: "warrior", race: "human", origin: "nordveld", age: "middle", portrait: "ragnar_bjornsen", foodPreference: "sweet", backstory: "Ragnar was the pride of Bjornsen — strongest boy on the island, champion of the summer games — but pride doesn't fill a grain store, and after the third failed harvest, he took his strength where it could earn bread." },
  { id: "char_141", name: "Hrothgar Frostvik", class: "warrior", race: "human", origin: "nordveld", age: "old", portrait: "hrothgar_frostvik", foodPreference: "spicy", backstory: "Hrothgar has fought in more shield-walls than he can count and buried more friends than he'd like to; he came south because an old warrior with no farm and no family has nothing left but his sword-arm." },
  { id: "char_142", name: "Vidar Thorssen", class: "warrior", race: "human", origin: "nordveld", age: "young", portrait: "vidar_thorssen", foodPreference: "hearty", backstory: "Vidar has his father's build and his mother's stubbornness, which is why he left the islands at seventeen to prove he didn't need the Thorssen name to make his own saga." },
  { id: "char_143", name: "Eerika Stormvik", class: "wizard", race: "human", origin: "nordveld", age: "mature", portrait: "eerika_stormvik", foodPreference: "smoky", backstory: "Eerika was a völva who read the runes and mixed the old remedies until a Dominion trading post on the island's edge brought missionaries who called her work witchcraft — she left before they could bring Inquisitors." },
  { id: "char_144", name: "Saga Ravnskog", class: "wizard", race: "human", origin: "nordveld", age: "middle", portrait: "saga_ravnskog", foodPreference: "fresh", backstory: "Saga found she could still the wind by singing to it, a gift her grandmother said came from the old blood; she went south to learn what else her voice could do, far from those who'd fear it." },
  { id: "char_145", name: "Valdis Steinholm", class: "wizard", race: "human", origin: "nordveld", age: "middle", portrait: "valdis_steinholm", foodPreference: "sweet", backstory: "Valdis carved binding-runes on fishing nets that never came up empty, and when the other fishermen started calling it sorcery instead of skill, she took her knives and her knowledge elsewhere." },
  { id: "char_146", name: "Ketill Bjornsen", class: "wizard", race: "human", origin: "nordveld", age: "middle", portrait: "ketill_bjornsen", foodPreference: "spicy", backstory: "Ketill was a shipwright who discovered that certain old rune-patterns made hulls stronger than any timber had a right to be; when the jarl demanded he use the gift for warships, Ketill burned his workshop and left." },
  { id: "char_147", name: "Snorri Frostvik", class: "wizard", race: "human", origin: "nordveld", age: "old", portrait: "snorri_frostvik", foodPreference: "hearty", backstory: "Snorri has forgotten more rune-lore than most völvas ever learn, and he remembers enough to know that something ancient is stirring in the south — curiosity has always been his worst trait." },
  { id: "char_148", name: "Runolf Thorssen", class: "wizard", race: "human", origin: "nordveld", age: "young", portrait: "runolf_thorssen", foodPreference: "smoky", backstory: "Runolf accidentally set a longhouse on fire with a word he didn't know he was speaking, and his family sent him south before his gift killed someone — or before the fearful neighbors killed him." },
  { id: "char_149", name: "Caelwen Starweaver", class: "archer", race: "elf", origin: "silvaneth", age: "middle", portrait: "caelwen_starweaver", foodPreference: "fresh", backstory: "She watched the grey blight swallow the glade where she learned to shoot, and swore she would not stand sentinel over another dying tree." },
  { id: "char_150", name: "Faelan Moonshadow", class: "archer", race: "elf", origin: "silvaneth", age: "middle", portrait: "faelan_moonshadow", foodPreference: "sweet", backstory: "He left the Thornveil after his patrol partner walked into the Hollow Wastes and never returned — some griefs are easier to carry on a road that moves forward." },
  { id: "char_151", name: "Niamh Nightbloom", class: "assassin", race: "elf", origin: "silvaneth", age: "middle", portrait: "niamh_nightbloom", foodPreference: "spicy", backstory: "She was the one they sent to silence Silvaneth who strayed too close to the blight, until the night she was sent after someone she loved." },
  { id: "char_152", name: "Thalorin Dawnwhisper", class: "assassin", race: "elf", origin: "silvaneth", age: "middle", portrait: "thalorin_dawnwhisper", foodPreference: "hearty", backstory: "His name means \"dawn's whisper,\" but he learned his trade in the dark — tracking poachers who cut living wood from the ward-line to sell as curiosities." },
  { id: "char_153", name: "Aelindra Leafsong", class: "priest", race: "elf", origin: "silvaneth", age: "middle", portrait: "aelindra_leafsong", foodPreference: "smoky", backstory: "She sang the rites for a grove that died in a single night, roots blackened from below, and left because her prayers could not explain why." },
  { id: "char_154", name: "Sionaeve Starweaver", class: "priest", race: "elf", origin: "silvaneth", age: "old", portrait: "sionaeve_starweaver", foodPreference: "fresh", backstory: "She remembers when her people did not die of old age, and now she tends the dying with hands that tremble more each year." },
  { id: "char_155", name: "Brynmor Moonshadow", class: "priest", race: "elf", origin: "silvaneth", age: "middle", portrait: "brynmor_moonshadow", foodPreference: "sweet", backstory: "He was keeper of a sacred spring that went dry the same season three elders finally succumbed to age — he walks south seeking answers the forest no longer gives." },
  { id: "char_156", name: "Loranthiel Dawnwhisper", class: "priest", race: "elf", origin: "silvaneth", age: "middle", portrait: "loranthiel_dawnwhisper", foodPreference: "spicy", backstory: "He spent decades copying the old death-rites onto new bark, preserving funerary customs his people never needed before Le Déclin." },
  { id: "char_157", name: "Caelorin Leafsong", class: "priest", race: "elf", origin: "silvaneth", age: "old", portrait: "caelorin_leafsong", foodPreference: "hearty", backstory: "He held vigil at the Thornveil for longer than most settlements have existed, and left only when the ward-line dimmed enough that vigil felt like pretending." },
  { id: "char_158", name: "Eirenel Nightbloom", class: "warrior", race: "elf", origin: "silvaneth", age: "mature", portrait: "eirenel_nightbloom", foodPreference: "smoky", backstory: "She commanded the vanguard that held the western Thornveil for forty years, and stepped down when she realized she was fighting the blight, not the Wastes." },
  { id: "char_159", name: "Morwenna Starweaver", class: "warrior", race: "elf", origin: "silvaneth", age: "middle", portrait: "morwenna_starweaver", foodPreference: "fresh", backstory: "She carries a shield grown from heartwood of a tree that died defending the ward-line — it still bleeds sap when the blight draws near." },
  { id: "char_160", name: "Briallen Dawnwhisper", class: "warrior", race: "elf", origin: "silvaneth", age: "young", portrait: "briallen_dawnwhisper", foodPreference: "sweet", backstory: "Born after Le Déclin, she has never known immortality and refuses to grieve for it — she would rather build something new than mourn something she never had." },
  { id: "char_161", name: "Thandril Moonshadow", class: "warrior", race: "elf", origin: "silvaneth", age: "middle", portrait: "thandril_moonshadow", foodPreference: "spicy", backstory: "He broke formation during a Hollow Wastes incursion to carry a wounded scout to safety, and his commander called it desertion; he calls it the only order worth following." },
  { id: "char_162", name: "Gwyneira Leafsong", class: "wizard", race: "elf", origin: "silvaneth", age: "mature", portrait: "gwyneira_leafsong", foodPreference: "hearty", backstory: "She studied the grey blight for decades, mapping its slow advance through the root-network, until her own laboratory tree began to wither around her." },
  { id: "char_163", name: "Eilonwy Nightbloom", class: "wizard", race: "elf", origin: "silvaneth", age: "middle", portrait: "eilonwy_nightbloom", foodPreference: "smoky", backstory: "She can feel the forest's pain like a second pulse, and left the canopy because the constant ache of dying trees was drowning out her own thoughts." },
  { id: "char_164", name: "Aerendir Starweaver", class: "wizard", race: "elf", origin: "silvaneth", age: "middle", portrait: "aerendir_starweaver", foodPreference: "fresh", backstory: "His research into reversing the blight was declared dangerous by the grove council — they feared his methods involved waking things in the Hollow Wastes that should stay sleeping." },
  { id: "char_165", name: "Maelorin Moonshadow", class: "wizard", race: "elf", origin: "silvaneth", age: "old", portrait: "maelorin_moonshadow", foodPreference: "sweet", backstory: "He is old enough to remember casting spells that drew on the death god's power, and wise enough to know that the silence where that power was is the most dangerous thing in the world." },
  { id: "char_166", name: "Coravel Dawnwhisper", class: "wizard", race: "elf", origin: "silvaneth", age: "young", portrait: "coravel_dawnwhisper", foodPreference: "spicy", backstory: "He grew up in a tree that was already half-grey, and learned magic by studying what kept the living half alive — his optimism unsettles older Silvaneth." },
  { id: "char_167", name: "Daiyu Zhang", class: "archer", race: "human", origin: "tianzhou", age: "mature", portrait: "daiyu_zhang", foodPreference: "hearty", backstory: "A retired imperial cartographer who mapped the western frontier for the Jade Court, then refused to falsify borders when a general demanded it. Her maps were burned; she kept the skills." },
  { id: "char_168", name: "Lian Chen", class: "archer", race: "human", origin: "tianzhou", age: "middle", portrait: "lian_chen", foodPreference: "smoky", backstory: "Grew up hunting in the bamboo forests outside a garrison town, selling pelts to fund her younger brother's education. When he earned his scholar's post and no longer needed her, she realized she'd never learned how to need anything but the next hunt." },
  { id: "char_169", name: "Meiling Liu", class: "archer", race: "human", origin: "tianzhou", age: "young", portrait: "meiling_liu", foodPreference: "fresh", backstory: "A courier's daughter who can split a reed at sixty paces, sent west by her mother to escape a magistrate's unwanted marriage proposal. She was told to stay gone until the political winds changed." },
  { id: "char_170", name: "Wei Wang", class: "archer", race: "human", origin: "tianzhou", age: "mature", portrait: "wei_wang", foodPreference: "sweet", backstory: "Served as an imperial border warden for twenty years with a spotless record, then was reassigned to a desk when a new governor's nephew wanted his post. He resigned rather than stamp papers while the frontier burned." },
  { id: "char_171", name: "Zheng Li", class: "archer", race: "human", origin: "tianzhou", age: "middle", portrait: "zheng_li", foodPreference: "spicy", backstory: "A merchant marine who deserted his trade vessel after discovering his captain was smuggling slaves below the silk cargo. The Jade Court considers desertion a capital offense regardless of the reason." },
  { id: "char_172", name: "Bowen Yang", class: "archer", race: "human", origin: "tianzhou", age: "middle", portrait: "bowen_yang", foodPreference: "hearty", backstory: "A provincial hunting master who accidentally killed a protected imperial crane during a governor's banquet hunt. The governor laughed it off; the governor's wife did not. He was on a ship west before the warrant was signed." },
  { id: "char_173", name: "Xiulan Zhang", class: "assassin", race: "human", origin: "tianzhou", age: "middle", portrait: "xiulan_zhang", foodPreference: "smoky", backstory: "Trained in the Jade Court's diplomatic service — the branch that handles problems too delicate for soldiers. Her last assignment required killing a woman who turned out to be her childhood tutor, and she completed it. She left because she completed it." },
  { id: "char_174", name: "Yanmei Huang", class: "assassin", race: "human", origin: "tianzhou", age: "middle", portrait: "yanmei_huang", foodPreference: "fresh", backstory: "A silk merchant's daughter who poisoned a corrupt tax collector who had bled her family dry for years. The crime was perfect; her conscience was not, and she fled west carrying guilt heavier than any bounty." },
  { id: "char_175", name: "Jingfei Zhou", class: "assassin", race: "human", origin: "tianzhou", age: "middle", portrait: "jingfei_zhou", foodPreference: "sweet", backstory: "A former magistrate's investigator who spent decades solving murders, until the evidence in her last case pointed at the magistrate himself. She presented her findings; he presented a death warrant. She was faster." },
  { id: "char_176", name: "Haoran Wang", class: "assassin", race: "human", origin: "tianzhou", age: "mature", portrait: "haoran_wang", foodPreference: "spicy", backstory: "Once a palace shadow-guard sworn to protect the Emperor's bloodline, until he uncovered a succession plot and chose the wrong prince to warn. The winning prince has a long memory." },
  { id: "char_177", name: "Feng Li", class: "assassin", race: "human", origin: "tianzhou", age: "middle", portrait: "feng_li", foodPreference: "hearty", backstory: "A calligrapher's apprentice with unnervingly steady hands who fell into debt with a river gang and paid it off with skills no calligrapher should have. Now the gang wants him permanent, and he wants to be anywhere else." },
  { id: "char_178", name: "Lanying Chen", class: "priest", race: "human", origin: "tianzhou", age: "mature", portrait: "lanying_chen", foodPreference: "smoky", backstory: "A temple physician who served the imperial court for fifteen years, quietly healing servants and nobles alike. When she publicly refused to let a concubine die of \"natural causes\" as ordered, she lost her post and nearly her life." },
  { id: "char_179", name: "Mingzhu Liu", class: "priest", race: "human", origin: "tianzhou", age: "middle", portrait: "mingzhu_liu", foodPreference: "fresh", backstory: "A monastery-trained healer who believes the Jade Court's rigid hierarchies cause more suffering than they prevent. She publishes her heretical medical texts under a false name, and the real one has traveled far enough west to be safe." },
  { id: "char_180", name: "Ruolan Yang", class: "priest", race: "human", origin: "tianzhou", age: "young", portrait: "ruolan_yang", foodPreference: "sweet", backstory: "An astronomer's apprentice who predicted an eclipse the imperial observatory missed, embarrassing her superiors. They called it luck; she called it mathematics. Either way, her scholarship was revoked." },
  { id: "char_181", name: "Changming Zhang", class: "priest", race: "human", origin: "tianzhou", age: "middle", portrait: "changming_zhang", foodPreference: "spicy", backstory: "A wandering monk who left his order after discovering the abbot was selling temple medicines to warlords instead of distributing them to the sick. He took the recipe scrolls with him and considers it a rescue, not a theft." },
  { id: "char_182", name: "Junshan Huang", class: "priest", race: "human", origin: "tianzhou", age: "middle", portrait: "junshan_huang", foodPreference: "hearty", backstory: "A court physician who healed a political prisoner without authorization, arguing that his oath preceded any imperial directive. The tribunal disagreed, and he was given a choice: exile or re-education. He chose the sea." },
  { id: "char_183", name: "Shenwei Zhou", class: "priest", race: "human", origin: "tianzhou", age: "old", portrait: "shenwei_zhou", foodPreference: "smoky", backstory: "The oldest surviving scholar of the Celestial Archive, exiled forty years ago for publishing a history that contradicted the dynasty's official account. He has outlived three emperors and still insists he was right." },
  { id: "char_184", name: "Huifen Wang", class: "warrior", race: "human", origin: "tianzhou", age: "middle", portrait: "huifen_wang", foodPreference: "fresh", backstory: "A garrison commander's daughter who earned her rank through merit, then watched it stripped away when her father fell from political favor. She kept her sword and her pride; the Jade Court kept everything else." },
  { id: "char_185", name: "Baihe Li", class: "warrior", race: "human", origin: "tianzhou", age: "middle", portrait: "baihe_li", foodPreference: "sweet", backstory: "A career soldier who defended the same river crossing for twelve years, only to be reassigned when the empire ceded the territory in a treaty. She couldn't watch someone else's flag fly over ground her friends died for." },
  { id: "char_186", name: "Suyin Chen", class: "warrior", race: "human", origin: "tianzhou", age: "young", portrait: "suyin_chen", foodPreference: "spicy", backstory: "Failed the imperial officer examinations by one mark and was told to wait another three years to retake them. She'd rather prove herself with a blade than a brush." },
  { id: "char_187", name: "Guowei Liu", class: "warrior", race: "human", origin: "tianzhou", age: "middle", portrait: "guowei_liu", foodPreference: "hearty", backstory: "A strategist who won three campaigns for the Jade Court and was rewarded with a provincial governorship he never asked for. He abandoned the post within a month — he knows how to take a city, not run one." },
  { id: "char_188", name: "Tielong Yang", class: "warrior", race: "human", origin: "tianzhou", age: "old", portrait: "tielong_yang", foodPreference: "smoky", backstory: "A retired general who came west to die somewhere quiet, then found he wasn't ready to stop fighting. He is appalled by western swordsmanship and considers it his personal obligation to demonstrate proper form." },
  { id: "char_189", name: "Jianyu Zhang", class: "warrior", race: "human", origin: "tianzhou", age: "young", portrait: "jianyu_zhang", foodPreference: "fresh", backstory: "Youngest son of a disgraced military family, carrying a name that closes doors across the Jade Empire. He crossed the sea to find a place where Zhang means nothing and his sword arm means everything." },
  { id: "char_190", name: "Yueliang Huang", class: "wizard", race: "human", origin: "tianzhou", age: "middle", portrait: "yueliang_huang", foodPreference: "sweet", backstory: "A court astrologer who read the stars honestly and told the empress her dynasty would end within a generation. The empress thanked her for her service and suggested she enjoy it somewhere far, far away." },
  { id: "char_191", name: "Zhenyi Zhou", class: "wizard", race: "human", origin: "tianzhou", age: "old", portrait: "zhenyi_zhou", foodPreference: "spicy", backstory: "Spent her life cataloging every known spell in the imperial library, then discovered that entire sections had been deliberately erased by previous dynasties. She left to find what was missing, horrified by what her own institution had destroyed." },
  { id: "char_192", name: "Linxia Wang", class: "wizard", race: "human", origin: "tianzhou", age: "young", portrait: "linxia_wang", foodPreference: "hearty", backstory: "A prodigy who manifested elemental magic during her entrance examinations at the Academy, shattering every window in the testing hall. The Academy offered admission; the dean's office offered a damage bill. She couldn't afford either." },
  { id: "char_193", name: "Qingyun Li", class: "wizard", race: "human", origin: "tianzhou", age: "middle", portrait: "qingyun_li", foodPreference: "smoky", backstory: "A philosophical mage who argues that western \"wild magic\" and eastern \"cultivated arts\" are the same force wearing different clothes. The Academy expelled him for this heresy. He intends to prove them wrong." },
  { id: "char_194", name: "Daoming Chen", class: "wizard", race: "human", origin: "tianzhou", age: "old", portrait: "daoming_chen", foodPreference: "fresh", backstory: "A retired imperial alchemist who spent decades refining elixirs of longevity for the court, and swears he never actually gave one to the empress. The Jade Court's investigators remain unconvinced." },
  { id: "char_195", name: "Wuji Liu", class: "wizard", race: "human", origin: "tianzhou", age: "young", portrait: "wuji_liu", foodPreference: "sweet", backstory: "An apprentice who accidentally opened a rift during a supervised exercise and glimpsed something on the other side that smiled back. His masters sealed the rift; he sealed his bags and left before anyone could ask what he saw." },
  { id: "char_196", name: "Amara Mensah", class: "archer", race: "human", origin: "zahkari", age: "mature", portrait: "amara_mensah", foodPreference: "spicy", backstory: "Won the Silver Arrow at the War Games three years running, then watched her apprentice die on a hunt she'd planned. She walks the frontier now, where no one calls her champion." },
  { id: "char_197", name: "Zuri Adeyemi", class: "archer", race: "human", origin: "zahkari", age: "middle", portrait: "zuri_adeyemi", foodPreference: "hearty", backstory: "Trained as a border scout for the Adeyemi council seat, but fell in love with a Dominion trader her elders would never accept. She chose exile over apology." },
  { id: "char_198", name: "Ama Boateng", class: "archer", race: "human", origin: "zahkari", age: "young", portrait: "ama_boateng", foodPreference: "smoky", backstory: "Ran away the night before her betrothal ceremony with nothing but her grandmother's shortbow. She figures the frontier is far enough that no one will come looking." },
  { id: "char_199", name: "Kofi Okafor", class: "archer", race: "human", origin: "zahkari", age: "mature", portrait: "kofi_okafor", foodPreference: "fresh", backstory: "Served twenty years as a gate warden of Okafor's Wall, then let a refugee column through against direct orders. The council called it treason; he calls it the only right thing he ever did." },
  { id: "char_200", name: "Kwame Diallo", class: "archer", race: "human", origin: "zahkari", age: "middle", portrait: "kwame_diallo", foodPreference: "sweet", backstory: "The elders groomed him for the War Games, but he broke his rival's spine with a careless shot during practice. He left before dawn and hasn't drawn a competition bow since." },
  { id: "char_201", name: "Jabari Asante", class: "archer", race: "human", origin: "zahkari", age: "middle", portrait: "jabari_asante", foodPreference: "spicy", backstory: "A master fletcher whose workshop burned down with all his savings inside — an accident, or so his business partner claimed. He'd rather start over somewhere no one knows the Asante name." },
  { id: "char_202", name: "Esi Mensah", class: "assassin", race: "human", origin: "zahkari", age: "middle", portrait: "esi_mensah", foodPreference: "hearty", backstory: "Grew up running messages between rival council families in the night markets, learning who could be bought and who had to be avoided. When one family tried to buy her silence permanently, she decided to sell her skills somewhere less familiar." },
  { id: "char_203", name: "Adaeze Traore", class: "assassin", race: "human", origin: "zahkari", age: "middle", portrait: "adaeze_traore", foodPreference: "smoky", backstory: "Spent fifteen years as a judicial enforcer, hunting oath-breakers for the elder councils. The last target she was sent after turned out to be innocent — she buried the evidence and buried her career with it." },
  { id: "char_204", name: "Nkechi Okafor", class: "assassin", race: "human", origin: "zahkari", age: "old", portrait: "nkechi_okafor", foodPreference: "fresh", backstory: "They called her the Whisper of Okafor before she retired, and for two decades she was content to tend her garden. Then someone murdered her grandson, and the elders told her to let the courts handle it. She chose a different kind of justice." },
  { id: "char_205", name: "Emeka Adeyemi", class: "assassin", race: "human", origin: "zahkari", age: "mature", portrait: "emeka_adeyemi", foodPreference: "sweet", backstory: "Born into a family of champion duelists, he was the quiet one who preferred poisons to pageantry. When his methods came to light during a War Games scandal, he left before disgrace could touch his sisters." },
  { id: "char_206", name: "Tendai Diallo", class: "assassin", race: "human", origin: "zahkari", age: "middle", portrait: "tendai_diallo", foodPreference: "spicy", backstory: "Caught spying on a rival city-state's council on behalf of his own elders, then discovered his elders had no intention of retrieving him. He escaped the prison pit himself and owes loyalty to no council now." },
  { id: "char_207", name: "Sekou Boateng", class: "assassin", race: "human", origin: "zahkari", age: "young", portrait: "sekou_boateng", foodPreference: "hearty", backstory: "A dockworker's son who learned to pick locks and climb walls for fun, until a thieves' guild recruited him and a job went wrong. He's seventeen and already has a man's death on his hands." },
  { id: "char_208", name: "Abena Asante", class: "priest", race: "human", origin: "zahkari", age: "middle", portrait: "abena_asante", foodPreference: "smoky", backstory: "Served as keeper of the ancestral flame in Asante's great hall until she prophesied the elder patriarch's death — correctly. The family blamed her for the curse rather than thanking her for the warning." },
  { id: "char_209", name: "Yaa Mensah", class: "priest", race: "human", origin: "zahkari", age: "middle", portrait: "yaa_mensah", foodPreference: "fresh", backstory: "A battlefield healer who followed Zah'kari champions through three border wars, patching wounds she was never thanked for. She left when she realized she'd stopped praying for peace and started praying for it to end any way it could." },
  { id: "char_210", name: "Kwaku Traore", class: "priest", race: "human", origin: "zahkari", age: "mature", portrait: "kwaku_traore", foodPreference: "sweet", backstory: "An elder-priest who interpreted law for the Traore council for decades, until his own ruling forced his daughter into exile. He followed her, leaving his seat empty and his reputation in ruins." },
  { id: "char_211", name: "Olu Okafor", class: "priest", race: "human", origin: "zahkari", age: "middle", portrait: "olu_okafor", foodPreference: "spicy", backstory: "Trained in the great oracle house of Okafor, but his visions showed him things the elders didn't want spoken aloud. They offered him silence or exile — he chose the road." },
  { id: "char_212", name: "Dayo Adeyemi", class: "priest", race: "human", origin: "zahkari", age: "young", portrait: "dayo_adeyemi", foodPreference: "hearty", backstory: "An acolyte who healed a condemned prisoner the night before execution, believing all life was sacred. The elders disagreed, and his temple name was struck from the rolls before sunrise." },
  { id: "char_213", name: "Akosua Diallo", class: "warrior", race: "human", origin: "zahkari", age: "middle", portrait: "akosua_diallo", foodPreference: "smoky", backstory: "A War Games quarterfinalist who challenged a sitting elder's champion to an unsanctioned duel over a crooked ruling. She won the fight and lost her standing in the same breath." },
  { id: "char_214", name: "Nana Boateng", class: "warrior", race: "human", origin: "zahkari", age: "middle", portrait: "nana_boateng", foodPreference: "fresh", backstory: "Commanded a border garrison for a decade and never lost a skirmish, but her own soldiers accused her of hoarding rations during the dry season. True or not, the accusation was enough to end her career." },
  { id: "char_215", name: "Folake Asante", class: "warrior", race: "human", origin: "zahkari", age: "middle", portrait: "folake_asante", foodPreference: "sweet", backstory: "Rose through the warrior ranks despite being born to a weaver family, only to discover the council had been using her unit as expendable bait in border negotiations. She broke her oath-spear in the council hall and walked out." },
  { id: "char_216", name: "Adjoa Mensah", class: "warrior", race: "human", origin: "zahkari", age: "old", portrait: "adjoa_mensah", foodPreference: "spicy", backstory: "A legendary shield-captain who buried two husbands and three daughters to war and plague. She left the city-states because the walls started to feel less like protection and more like a tomb." },
  { id: "char_217", name: "Chukwu Traore", class: "warrior", race: "human", origin: "zahkari", age: "mature", portrait: "chukwu_traore", foodPreference: "hearty", backstory: "Won the War Games grand melee in his prime, then spent years as a council bodyguard watching politicians undo everything soldiers bled for. He took his axe and his pension and went looking for a fight that mattered." },
  { id: "char_218", name: "Obasi Okafor", class: "warrior", race: "human", origin: "zahkari", age: "middle", portrait: "obasi_okafor", foodPreference: "smoky", backstory: "Youngest son of a minor champion family, always living in his brothers' shadows at the War Games. He figured if he couldn't be first in Okafor, he'd be first somewhere else." },
  { id: "char_219", name: "Kojo Adeyemi", class: "warrior", race: "human", origin: "zahkari", age: "young", portrait: "kojo_adeyemi", foodPreference: "fresh", backstory: "Failed his warrior trials twice — not from lack of skill, but from freezing when he had to land the killing blow on the trial-boar. He came west to find courage away from the eyes of his father's legacy." },
  { id: "char_220", name: "Efua Diallo", class: "wizard", race: "human", origin: "zahkari", age: "mature", portrait: "efua_diallo", foodPreference: "sweet", backstory: "Once sat on the Diallo council as their star-reader, charting the movements of armies and monsoons. When her prediction of a flood was ignored and hundreds died, she swore she'd never advise the powerful again." },
  { id: "char_221", name: "Aminata Boateng", class: "wizard", race: "human", origin: "zahkari", age: "middle", portrait: "aminata_boateng", foodPreference: "spicy", backstory: "A prodigy who could call lightning before she could write her own name, but her power outgrew every mentor the city-states could offer. She crossed the border seeking knowledge the elders said was best left buried." },
  { id: "char_222", name: "Nneka Asante", class: "wizard", race: "human", origin: "zahkari", age: "young", portrait: "nneka_asante", foodPreference: "hearty", backstory: "Her magic manifested during a council feast when she accidentally set the ancestral tapestries on fire. The Asante elders were understanding; their champion guard was not. She took the hint and left." },
  { id: "char_223", name: "Gyasi Mensah", class: "wizard", race: "human", origin: "zahkari", age: "middle", portrait: "gyasi_mensah", foodPreference: "smoky", backstory: "An engineer-mage who designed fortifications for three city-states, until one of his walls collapsed and killed the workers inside. Whether it was his fault or sabotage, he couldn't stay to find out." },
  { id: "char_224", name: "Annan Traore", class: "wizard", race: "human", origin: "zahkari", age: "old", portrait: "annan_traore", foodPreference: "fresh", backstory: "The oldest living graduate of the Traore war-college, who spent fifty years perfecting a shield-ward that could stop any siege weapon. He left because no one would fund it, and he refuses to die before seeing it tested." },
  { id: "char_225", name: "Kwesi Okafor", class: "wizard", race: "human", origin: "zahkari", age: "young", portrait: "kwesi_okafor", foodPreference: "sweet", backstory: "A student who stole a forbidden text from the Okafor archive because he was certain the elders were hiding knowledge that could help people. He was right about the hiding, wrong about getting away with it." },
];

